class Solution:
    def incremovableSubarrayCount(self, nums):
        n = len(nums)
        count = 0
        for i in range(n):
            for j in range(i, n):
                rest = nums[:i] + nums[j + 1:]
                ok = True
                for k in range(len(rest) - 1):
                    if rest[k] >= rest[k + 1]:
                        ok = False
                        break
                if ok:
                    count += 1
        return count

