class Solution:
    def incremovableSubarrayCount(self, nums):
        n = len(nums)
        prefixLen = 1
        while prefixLen < n and nums[prefixLen - 1] < nums[prefixLen]:
            prefixLen += 1
        if prefixLen == n:
            return n * (n + 1) // 2
        suffixStart = n - 1
        while suffixStart > 0 and nums[suffixStart - 1] < nums[suffixStart]:
            suffixStart -= 1
        count = 0
        right = suffixStart
        for left in range(0, prefixLen + 1):
            if left > 0:
                while right < n and nums[right] <= nums[left - 1]:
                    right += 1
            if right < left:
                right = left
            count += n - right + 1
        return count

