var incremovableSubarrayCount = function(nums) {
    const n = nums.length;
    let prefixLen = 1;
    while (prefixLen < n && nums[prefixLen - 1] < nums[prefixLen]) {
        prefixLen += 1;
    }
    if (prefixLen === n) {
        return (n * (n + 1)) / 2;
    }
    let suffixStart = n - 1;
    while (suffixStart > 0 && nums[suffixStart - 1] < nums[suffixStart]) {
        suffixStart -= 1;
    }
    let count = 0;
    let right = suffixStart;
    for (let left = 0; left <= prefixLen; left++) {
        if (left > 0) {
            while (right < n && nums[right] <= nums[left - 1]) {
                right += 1;
            }
        }
        if (right < left) {
            right = left;
        }
        count += n - right + 1;
    }
    return count;
};
